  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import { getLegacyObserveState, usePerspective } from '../hooks/usePerspective';
  4	import { Alerts, AlertSource } from '../types';
  5	import { useSelector } from 'react-redux';
  6	
  7	import * as _ from 'lodash-es';
  8	import {
  9	  alertCluster,
 10	  alertingRuleSource,
 11	  alertSource,
 12	  getAdditionalSources,
 13	  SilencesNotLoadedWarning,
 14	} from './AlertUtils';
 15	import {
 16	  AlertSeverity,
 17	  AlertStates,
 18	  ListPageFilter,
 19	  RowFilter,
 20	  useListPageFilter,
 21	} from '@openshift-console/dynamic-plugin-sdk';
 22	import { fuzzyCaseInsensitive } from '../utils';
 23	import { Table, TableGridBreakpoint, Th, Thead, Tr } from '@patternfly/react-table';
 24	import { Helmet } from 'react-helmet';
 25	import { MonitoringState } from '../../reducers/observe';
 26	import { EmptyBox } from '../console/console-shared/src/components/empty-state/EmptyBox';
 27	import withFallback from '../console/console-shared/error/fallbacks/withFallback';
 28	import { LoadingBox } from '../console/console-shared/src/components/loading/LoadingBox';
 29	import { AggregatedAlert, getAggregateAlertsLists } from './AlertsAggregates';
 30	
 31	import './alert-table.scss';
 32	import Error from './Error';
 33	import AggregateAlertTableRow from './AlertList/AggregateAlertTableRow';
 34	import useAggregateAlertColumns from './AlertList/hooks/useAggregateAlertColumns';
 35	import useSelectedFilters from './useSelectedFilters';
 36	
 37	import './alert-table.scss';
 38	import { PageSection, PageSectionVariants } from '@patternfly/react-core';
 39	
 40	const AlertsPage_: React.FC = () => {
 41	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 42	  const { alertsKey, silencesKey, defaultAlertTenant, perspective } = usePerspective();
 43	
 44	  const {
 45	    data,
 46	    loaded = false,
 47	    loadError,
 48	  }: Alerts = useSelector(
 49	    (state: MonitoringState) => getLegacyObserveState(perspective, state)?.get(alertsKey) || {},
 50	  );
 51	  const silencesLoadError = useSelector(
 52	    (state: MonitoringState) =>
 53	      getLegacyObserveState(perspective, state)?.get(silencesKey)?.loadError,
 54	  );
 55	
 56	  const aggregatedAlertsList = getAggregateAlertsLists(data);
 57	
 58	  const alertAdditionalSources = React.useMemo(
 59	    () => getAdditionalSources(data, alertSource),
 60	    [data],
 61	  );
 62	
 63	  const clusters = React.useMemo(() => {
 64	    const clusterSet = new Set<string>();
 65	    data?.forEach((alert) => {
 66	      const clusterName = alert.labels?.cluster;
 67	      if (clusterName) {
 68	        clusterSet.add(clusterName);
 69	      }
 70	    });
 71	
 72	    const clusterArray = Array.from(clusterSet);
 73	    return clusterArray.sort();
 74	  }, [data]);
 75	
 76	  let rowFilters: RowFilter[] = [
 77	    // TODO: The "name" filter doesn't really fit useListPageFilter's idea of a RowFilter, but
 78	    //       useListPageFilter doesn't yet provide a better way to add a filter like this
 79	    {
 80	      filter: (filter, alert: AggregatedAlert) =>
 81	        fuzzyCaseInsensitive(filter.selected?.[0], alert.name),
 82	      filterGroupName: '',
 83	      items: [],
 84	      type: 'name',
 85	    } as RowFilter,
 86	    {
 87	      defaultSelected: [AlertStates.Firing],
 88	      filter: (filter, aggregatedAlert: AggregatedAlert) =>
 89	        Array.from(aggregatedAlert.states).some((state) => filter.selected?.includes(state)) ||
 90	        _.isEmpty(filter.selected),
 91	      filterGroupName: t('Alert State'),
 92	      items: [
 93	        { id: AlertStates.Firing, title: t('Firing') },
 94	        { id: AlertStates.Pending, title: t('Pending') },
 95	        { id: AlertStates.Silenced, title: t('Silenced') },
 96	      ],
 97	      isMatch: (aggregatedAlert: AggregatedAlert, id: AlertStates) =>
 98	        aggregatedAlert.states.has(id),
 99	      type: 'alert-state',
100	    },
101	    {
102	      defaultSelected: [AlertStates.Firing],
103	      filter: (filter, aggregatedAlert: AggregatedAlert) =>
104	        _.isEmpty(filter.selected) || filter.selected?.includes(aggregatedAlert?.severity),
105	      filterGroupName: t('Severity'),
106	      items: [
107	        { id: AlertSeverity.Critical, title: t('Critical') },
108	        { id: AlertSeverity.Warning, title: t('Warning') },
109	        { id: AlertSeverity.Info, title: t('Info') },
110	        { id: AlertSeverity.None, title: t('None') },
111	      ],
112	      reducer: (aggregatedAlert: AggregatedAlert) => aggregatedAlert.severity,
113	      type: 'alert-severity',
114	    },
115	    {
116	      defaultSelected: defaultAlertTenant,
117	      filter: (filter, aggregatedAlert: AggregatedAlert) =>
118	        aggregatedAlert.alerts.some((alert) => filter.selected?.includes(alertSource(alert))) ||
119	        _.isEmpty(filter.selected),
120	      filterGroupName: t('Source'),
121	      items: [
122	        { id: AlertSource.Platform, title: t('Platform') },
123	        { id: AlertSource.User, title: t('User') },
124	        ...alertAdditionalSources,
125	      ],
126	      isMatch: (aggregatedAlert: AggregatedAlert, id: AlertSource) =>
127	        aggregatedAlert.alerts.some((alert) => id === alertingRuleSource(alert.rule)),
128	      type: 'alert-source',
129	    },
130	  ];
131	
132	  if (perspective === 'dev') {
133	    rowFilters = rowFilters.filter((filter) => filter.type !== 'alert-source');
134	  } else if (perspective === 'acm') {
135	    rowFilters.splice(-1, 0, {
136	      type: 'alert-cluster',
137	      filter: (filter, aggregatedAlert: AggregatedAlert) =>
138	        aggregatedAlert.alerts.some(
139	          (alert) =>
140	            filter.selected.length === 0 ||
141	            filter.selected.some((selectedFilter) =>
142	              fuzzyCaseInsensitive(selectedFilter, alert.labels?.cluster),
143	            ),
144	        ),
145	      filterGroupName: t('Cluster'),
146	      items: clusters.map((clusterName) => ({ id: clusterName, title: clusterName })),
147	      isMatch: (aggregatedAlert: AggregatedAlert, clusterName: string) =>
148	        aggregatedAlert.alerts.some((alert) =>
149	          fuzzyCaseInsensitive(clusterName, alert.labels?.cluster),
150	        ),
151	      reducer: alertCluster,
152	    } as RowFilter);
153	  }
154	
155	  const [staticData, filteredData, onFilterChange] = useListPageFilter(
156	    aggregatedAlertsList,
157	    rowFilters,
158	  );
159	
160	  const columns = useAggregateAlertColumns();
161	  const selectedFilters = useSelectedFilters();
162	
163	  return (
164	    <>
165	      <Helmet>
166	        <title>Alerting</title>
167	      </Helmet>
168	      <PageSection variant={PageSectionVariants.light}>
169	        <ListPageFilter
170	          data={staticData}
171	          labelFilter="alerts"
172	          labelPath="labels"
173	          loaded={loaded}
174	          onFilterChange={onFilterChange}
175	          rowFilters={rowFilters}
176	        />
177	        {silencesLoadError && <SilencesNotLoadedWarning silencesLoadError={silencesLoadError} />}
178	
179	        {filteredData?.length > 0 && loaded && (
180	          <Table gridBreakPoint={TableGridBreakpoint.none} role="presentation">
181	            <Thead>
182	              <Tr>
183	                {columns.map((column) => (
184	                  <Th key={column.id} {...column?.props}>
185	                    {column.title}
186	                  </Th>
187	                ))}
188	              </Tr>
189	            </Thead>
190	            {filteredData.map((aggregatedAlert, index) => (
191	              <AggregateAlertTableRow
192	                key={aggregatedAlert.name}
193	                aggregatedAlert={aggregatedAlert}
194	                rowData={{ rowIndex: index, selectedFilters }}
195	              />
196	            ))}
197	          </Table>
198	        )}
199	
200	        {loadError && <Error error={loadError} />}
201	        {loaded && filteredData?.length === 0 && !loadError && <EmptyBox label={t('Alerts')} />}
202	        {!loaded && <LoadingBox />}
203	      </PageSection>
204	    </>
205	  );
206	};
207	const AlertsPage = withFallback(AlertsPage_);
208	
209	export default AlertsPage;

